SELECT EXISTS(
  SELECT 1
  FROM public_reservations
  WHERE reservation_date = #{reservationDate}
    AND time_slot = #{timeSlot}
    AND guide_language = #{guideLanguage}
)

SELECT COALESCE(SUM(guest_count), 0)
FROM public_reservations
WHERE reservation_date = #{reservationDate}
  AND time_slot = #{timeSlot}
  AND guide_language = #{guideLanguage}
